CREATE INDEX CONCURRENTLY IF NOT EXISTS idx_analytics_dim_option_slm
    ON analytics.dim_option (source_last_modified_at);
CREATE UNIQUE INDEX CONCURRENTLY IF NOT EXISTS idx_analytics_dim_option_uid_uniq
    ON analytics.dim_option (option_uid);
CREATE INDEX CONCURRENTLY IF NOT EXISTS idx_analytics_dim_option_slm_uid
    ON analytics.dim_option (source_last_modified_at, option_uid);
